var suggestions=document.getElementById('suggestions'),search=document.getElementById('search');search!==null&&document.addEventListener('keydown',inputFocus);function inputFocus(a){a.ctrlKey&&a.key==='/'&&(a.preventDefault(),search.focus()),a.key==='Escape'&&(search.blur(),suggestions.classList.add('d-none'))}document.addEventListener('click',function(a){var b=suggestions.contains(a.target);b||suggestions.classList.add('d-none')}),document.addEventListener('keydown',suggestionFocus);function suggestionFocus(c){const d=suggestions.classList.contains('d-none');if(d)return;const a=[...suggestions.querySelectorAll('a')];if(a.length===0)return;const b=a.indexOf(document.activeElement);if(c.key==="ArrowUp"){c.preventDefault();const d=b>0?b-1:0;a[d].focus()}else if(c.key==="ArrowDown"){c.preventDefault();const d=b+1<a.length?b+1:b;a[d].focus()}}(function(){var a=new FlexSearch.Document({tokenize:"forward",cache:100,document:{id:'id',store:["href","title","description"],index:["title","description","content"]}});a.add({id:0,href:"/docs/prologue/introduction/",title:"Introduction",description:"Doks is a Hugo theme for building secure, fast, and SEO-ready documentation websites, which you can easily update and customize.",content:"Get started # There are two main ways to get started with Doks:\nTutorial # Step-by-step instructions on how to start a new Doks project. Tutorial →\nQuick Start # One page summary of how to start a new Doks project. Quick Start →\nGo further # Recipes, Reference Guides, Extensions, and Showcase.\nRecipes # Get instructions on how to accomplish common tasks with Doks. Recipes →\nReference Guides # Learn how to customize Doks to fully make it your own. Reference Guides →\nExtensions # Get instructions on how to add even more to Doks. Extensions →\nShowcase # See what others have build with Doks. Showcase →\nContributing # Find out how to contribute to Doks. Contributing →\nHelp # Get help on Doks. Help →\n"}).add({id:1,href:"/docs/prologue/quick-start/",title:"Quick Start",description:"One page summary of how to start a new Doks project.",content:"Requirements #  Git — latest source release Node.js — latest LTS version or newer  Why Node.js?\r\rDoks uses npm (included with Node.js) to centralize dependency management, making it easy to update resources, build tooling, plugins, and build scripts.\r\r\r\r Start a new Doks project # Create a new site, change directories, install dependencies, and start development server.\nCreate a new site # Doks is available as a child theme and a starter theme.\nChild theme #  Intended for novice to intermediate users Intended for minor customizations Easily update npm packages — including Doks  git clone https://github.com/h-enk/doks-child-theme.git my-doks-site  Starter theme #  Intended for intermediate to advanced users Intended for major customizations Easily update npm packages  git clone https://github.com/h-enk/doks.git my-doks-site  \u0026lt;nil\u0026gt;\r\rNot sure which one is for you? Pick the child theme.\r\r\r\r Change directories # cd my-doks-site  Install dependencies # npm install  Start development server # npm run start  Doks will start the Hugo development webserver accessible by default at http://localhost:1313. Saved changes will live reload in the browser.\nOther commands # Doks comes with commands for common tasks. Commands →\n"}).add({id:2,href:"/docs/prologue/commands/",title:"Commands",description:"Doks comes with commands for common tasks.",content:"create # Create new content for your site:\nnpm run create [path] [flags]  See also the Hugo docs: hugo new.\nDocs based tree # Create a docs based tree — with a single command:\nnpm run create -- --kind docs [section]  For example, create a docs based tree named guides:\nnpm run create -- --kind docs guides  lint # Check scripts, styles, and markdown for errors:\nnpm run lint  scripts # Check scripts for errors:\nnpm run lint:scripts [-- --fix]  styles # Check styles for errors:\nnpm run lint:styles [-- --fix]  markdown # Check markdown for errors:\nnpm run lint:markdown [-- --fix]  clean # Delete temporary directories:\nnpm run clean  start # Start local development server:\nnpm run start  build # Build production website:\nnpm run build  functions # Build Lambda functions:\nnpm run build:functions  preview # Build production website including draft and future content:\nnpm run build:preview   Components # Code blocks # function highlight(obj){ var orig = obj.style.color; obj.style.color = \u0026quot; #00FF00\u0026quot;; setTimeout(function(){ obj.style.background = \u0026quot;#454444\u0026quot;; }, 3000); }  from abc import abstractmethod # Our interface for class class CircleInterface: @abstractmehod def draw_circle(self): pass  Katex # This is an example of inline katex $\\frac{x}{y}$ with $\\frac{x}{y}$.\nThis is an example of math block of katex.\n$$ \\sin^2 + \\cos^2 = 1 $$  $$ \\sin^2 + \\cos^2 = 1 $$\nTabs # Tabs can be created using tabs shortcode passed with uniqueid and tab shortcode containing tab content. MacOS\rMacOS Content # Add a default page, documentation page, blog post or contributor page. Customize the homepage and 404 page.Linux\rLinux Content # Windows\rA sample content to check code in tabs.\ndef num(l): for i in l: print(i)  $$ \\sin^2 + \\cos^2 = 1 $$\n\nLists # Ordered List\n first second third  Unordered List\n first second third  Check item\n checked unchecked onemore unchecked  Panel # Panel can be created using panel shortcode. What is panel?\r\rA panel is a collapsible section This is a collapsible panel\r\r\r\r\nPanel can be by default remain expanded, by passing collapsed=\u0026quot;false\u0026quot; default is true. Code in panel\r\r\u0026lt;div class=\u0026quot;accordion-item\u0026quot;\u0026gt; \u0026lt;div class=\u0026quot;card-body\u0026quot;\u0026gt; Text to display \u0026lt;/div\u0026gt; \u0026lt;/div\u0026gt;  \r\r\r\nAlerts # Alert can be created using shortcode alert and passing type=\u0026quot;type-name\u0026quot;.\nIf type is not provided then \u0026quot;primary\u0026quot; is default. \r\rA Primary alert\nPrimary alert with type=\u0026quot;primary\u0026quot;\r\r\r\n\r\rA Sucess alert\nSucess alert with type=\u0026quot;success\u0026quot;\r\r\r \r\rA Danger alert\nDanger alert with type=\u0026quot;danger\u0026quot;\r\r\r \r\rA Warning alert\nWarning alert with type=\u0026quot;warning\u0026quot;\r\r\r  \rA Secondary alert\nSecondary alert with type=\u0026quot;secondary\u0026quot;. Can have link\r\r\r  \rSecondary alert with type=\u0026quot;secondary\u0026quot; with no title. The use of alert is to help reader guide on some of the most important points or make him aware.\r\r\r Say you have a two-column layout: a main column with content and a sidebar. Say it has a lot of content, with sections that requires scrolling. The sidebar column that is largely empty, such that you can safely put a position: sticky; table of contents over there for all that content in the main column. A fairly common pattern for documentation. Bramus Van Damme has a nice tutorial on all this, starting from semantic markup, implementing most of the functionality with HTML and CSS, and then doing the last bit of active nav enhancement with JavaScript. For example, if you don’t click yourself down to a section (where you might be able to get away with :target styling for active navigation), JavaScript is necessary to tell where you are scrolled to and to highlight the active navigation. That active bit is handled nicely with IntersectionObserver, which is, like, the perfect API for this.\nHere’s that result:\nSay you have a two-column layout: a main column with content and a sidebar. Say it has a lot of content, with sections that requires scrolling. The sidebar column that is largely empty, such that you can safely put a position: sticky; table of contents over there for all that content in the main column. A fairly common pattern for documentation. Bramus Van Damme has a nice tutorial on all this, starting from semantic markup, implementing most of the functionality with HTML and CSS, and then doing the last bit of active nav enhancement with JavaScript. For example, if you don’t click yourself down to a section (where you might be able to get away with :target styling for active navigation), JavaScript is necessary to tell where you are scrolled to and to highlight the active navigation. That active bit is handled nicely with IntersectionObserver, which is, like, the perfect API for this.\nHere’s that result:\nTables # Tables in markdown.\n   Heading 1 📝 Heading 2🤟 Heading 3 🎋     item 1 😶‍🌫️ item 2 item 3   item 3 $\\alpha = \\beta$ def    File Download # File download button using file shortcode with link argument. \rflower.mp4\r\rflower.mp4\r\r\r\rFile Download button can be provided with custom text using title argument.\n\rDjango manage.py commands\r\rhelp.txt\r\r\r\rReference Link # Reference Link can be used to refer to other pages in docs using ref shortcode. \rQuick Start\r\r/docs/prologue/quick-start/\r\r\r\rReference Link can also be passed with custom text using title argument. \rLet\u0026#39;s Begin\r\r/docs/prologue/introduction/\r\r\r\rWith Custom icon :icon-shortcode: using icon argument. Check emjoi cheat sheet for more. ❤️\rCommands\r\r/docs/prologue/commands/\r\r\r\rPlain Link to external site # Link button can be created using link shortcode. \rHugo Url parse function\r\rgohugo.io\r\r\r\rCan be passed with custom icon with argument icon. 📄\rCh 5 Getting started with pandas\r\rcolab.research.google.com\r\r\r\rPass a target argument to change the opened link target, default is _blank. This is an example when target=\u0026quot;_self\u0026quot;. \rAttribute a Target\r\rwww.w3schools.com\r\r\r\rBadge # Badges can be created using badge shortcode and passing a title to it.\n   Type (type) Example     primary (default) \rPrimary\r   success \rSuccess\r   danger \rDanger\r   warning \rWarning\r   secondary \rSecondary\r    Badges\u0026rsquo;s shape can also configured using shape argument\n   Shape (shape) Example     round (default) \rRounded Badge\r   square \rSquare Badge\r   pill \rPill Badge\r    Image # Images can be added using figure shortcode and caption is provided using caption argument.  Shinkansen (Image source: Wikipedia)\n  And some text after image looks like this.\n And can be added from external sources as well. (Source Wikipedia)\n  Youtube # Youtube video can be embedded using youtube shortcode with id argument provided as Video ID.   "}).add({id:3,href:"/docs/help/how-to-update/",title:"How to Update",description:"Regularly update the installed npm packages to keep your Doks website stable, usable, and secure.",content:"Check for outdated packages # The npm outdated command will check the registry to see if any (or, specific) installed packages are currently outdated:\nnpm outdated [[\u0026lt;@scope\u0026gt;/]\u0026lt;pkg\u0026gt; ...]  Update packages # The npm update command will update all the packages listed to the latest version (specified by the tag config), respecting semver:\nnpm update [\u0026lt;pkg\u0026gt;...]  "}).add({id:4,href:"/docs/help/troubleshooting/",title:"Troubleshooting",description:"Solutions to common problems.",content:"Problems updating npm packages # Delete the ./node_modules folder, and run again:\nnpm install  Problems with cache # Delete the temporary directories:\nnpm run clean  "}).add({id:5,href:"/docs/help/faq/",title:"FAQ",description:"Answers to frequently asked questions.",content:"Hyas? # Doks is a Hyas theme build by the creator of Hyas.\nFooter notice? # Please keep it in place.\nKeyboard shortcuts for search? #  focus: Ctrl + / select: ↓ and ↑ open: Enter close: Esc  Other documentation? #  Netlify Hugo  Can I get support? # Create a topic:\n Netlify Community Hugo Forums Doks Discussions  Contact the creator? # Send h-enk a message:\n Netlify Community Hugo Forums Doks Discussions  "}).add({id:6,href:"/docs/help/",title:"Help",description:"Help Doks.",content:""}).add({id:7,href:"/docs/prologue/",title:"Prologue",description:"Prologue Doks.",content:""}).add({id:8,href:"/docs/",title:"Docs",description:"Docs Doks.",content:""}),search.addEventListener('input',b,!0);function b(){var b,e;const d=5;b=this.value,e=a.search(b,{limit:d,enrich:!0});const c=new Map;for(const a of e.flatMap(a=>a.result)){if(c.has(a.doc.href))continue;c.set(a.doc.href,a.doc)}if(suggestions.innerHTML="",suggestions.classList.remove('d-none'),c.size===0&&b){const a=document.createElement('div');a.innerHTML=`No results for "<strong>${b}</strong>"`,a.classList.add("suggestion__no-results"),suggestions.appendChild(a);return}for(const[h,g]of c){const b=document.createElement('div');suggestions.appendChild(b);const a=document.createElement('a');a.href=h,b.appendChild(a);const e=document.createElement('span');e.textContent=g.title,e.classList.add("suggestion__title"),a.appendChild(e);const f=document.createElement('span');if(f.textContent=g.description,f.classList.add("suggestion__description"),a.appendChild(f),suggestions.appendChild(b),suggestions.childElementCount==d)break}}})(),window.addEventListener('DOMContentLoaded',()=>{const a=new IntersectionObserver(a=>{a.forEach(a=>{const b=a.target.getAttribute('id');a.intersectionRatio>0?document.querySelector(`#TableOfContents a[href="#${b}"]`).classList.add('side-active'):document.querySelector(`#TableOfContents a[href="#${b}"]`).classList.remove('side-active')})});toc=document.querySelectorAll('#TableOfContents a'),toc.forEach(function(b){var c=b.getAttribute("href"),d=document.querySelector(c);a.observe(d)})})